from typing import List

class Solution:
    def paintWalls(self, cost: List[int], time: List[int]) -> int:
        n = len(cost)
        dp = [0] + [float('inf')] * n

        for i in range(n):
            for j in range(n, -1, -1):
                if j >= time[i]:
                    dp[j] = min(dp[j], dp[j - time[i]] + cost[i])

        return dp[n]
